// Butt hinge — two flat leaves, three interlocking knuckles, continuous pin.
// Laid flat (open 180°). Pin axis along Y, leaves on the XY plane.
//
// Dimensions:
//   Leaf:   30 (X, from knuckle out) × 60 (Y) × 3 (Z thickness).
//   Knuckle: 8 mm OD, centered on Y axis at z = 4 (so bottom touches z=0).
//   Pin:    4 mm OD, runs through all knuckles + 1 mm cap each end.
//   Leaves are centered vertically at z = 4 (matching pin axis), so leaf
//     bottom = 2.5, top = 5.5. The knuckle OD (8) extends from z=0 to z=8,
//     so it cleanly engulfs the leaf edge and fuses (≥ 0.5 mm overlap).
//
// Leaves alternate ownership of knuckles:
//   - Leaf A (+X side): owns the middle 20 mm knuckle (Y ∈ [-10, 10]).
//   - Leaf B (−X side): owns the two outer 15 mm knuckles (Y ∈ [-30,-15] and [15,30]).
//
// Each leaf has two countersunk screw holes (3 mm dia, 0.5 mm top chamfer).
//
// IMPORTANT NOTE on primitive placement (caught the hard way):
//   - `BREP.box([w, d, h])`     → centered in X and Y, but base on Z=0
//     (so a [30, 60, 3] box spans x∈[-15,15], y∈[-30,30], z∈[0,3]).
//   - `BREP.cylinder(r, h)`     → centered on X and Y at origin, base on Z=0,
//     height along +Z.
//   So neither primitive is fully "centered at origin" — both have their
//   base flush with Z=0. Translate Z explicitly to position them.

const { BREP } = api;

// ---------------------------------------------------------------------------
// Constants
// ---------------------------------------------------------------------------
const LEAF_W      = 30;   // X span (knuckle-meet → outer edge)
const LEAF_L      = 60;   // Y length
const LEAF_T      = 3;    // Z thickness
const KNUCKLE_R   = 4;    // outer radius (8 mm diameter)
const PIN_R       = 2;    // pin radius (4 mm diameter)
const PIN_CAP     = 1;    // pin overhang past the knuckle row on each end

const PIN_Z       = KNUCKLE_R;             // pin axis height (= 4)
const LEAF_BOT    = PIN_Z - LEAF_T / 2;    // 2.5
const LEAF_TOP    = PIN_Z + LEAF_T / 2;    // 5.5

const SCREW_R     = 1.5;   // 3 mm screw clearance
const SCREW_CSK   = 0.5;   // countersink chamfer
const LEAF_FILLET = 1.5;   // outer-corner radius

// Knuckle ranges along Y. Outer 15 mm each, middle 20 mm.
const Y_OUT_L_MIN = -30, Y_OUT_L_MAX = -15;
const Y_MID_MIN   = -10, Y_MID_MAX   =  10;
const Y_OUT_R_MIN =  15, Y_OUT_R_MAX =  30;

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

// A knuckle is a cylinder along Y. BREP.cylinder is base-at-z=0, axis +Z.
// rotate(-90, X) sends +Z → +Y, so a cylinder of height `len` becomes a
// horizontal cylinder spanning y∈[0, len], cross-section centered at the
// origin in XZ. We then translate so its axis sits at (x=0, z=PIN_Z) and
// y∈[yMin, yMax].
function knuckle(yMin, yMax) {
  const len = yMax - yMin;
  return BREP.cylinder(KNUCKLE_R, len)
    .rotate(-90, [1, 0, 0])
    .translate([0, yMin, PIN_Z]);
}

// A leaf slab. xSign = +1 (+X) or −1 (−X). Pre-translate, the [LEAF_W,
// LEAF_L, LEAF_T] box spans x∈[-LEAF_W/2, LEAF_W/2], y∈[-LEAF_L/2, LEAF_L/2],
// z∈[0, LEAF_T]. We translate it so:
//   - X: outer edge at xSign*LEAF_W, inner edge at x=0 (knuckle line).
//   - Z: spans [LEAF_BOT, LEAF_TOP] (vertically centered on the pin axis).
function leafSlab(xSign) {
  return BREP.box([LEAF_W, LEAF_L, LEAF_T])
    .translate([xSign * LEAF_W / 2, 0, LEAF_BOT]);
}

// Screw hole: a cylinder running through the leaf thickness with 0.5 mm
// overshoot on top and bottom so the cut is clean on both faces.
function screwHole(x, y) {
  const overshoot = 0.5;
  return BREP.cylinder(SCREW_R, LEAF_T + 2 * overshoot)
    .translate([x, y, LEAF_BOT - overshoot]);
}

// ---------------------------------------------------------------------------
// Build one leaf: slab + owned knuckle(s) → fillet outer corners → cut
// screw holes → chamfer the top rim of each hole.
//
// Rule learned from replicad.md: apply fillet BEFORE boolean cuts when
// possible, so the fillet solver sees a clean edge graph.
// ---------------------------------------------------------------------------
function buildLeaf(xSign, ownedKnuckles) {
  const slab = leafSlab(xSign);
  const fused = BREP.fuseAll([slab, ...ownedKnuckles]);

  // Fillet only the two outer vertical corners of the leaf (far-X end,
  // both Y extremes). `inDirection: [0,0,1]` picks vertical edges only;
  // `minX`/`maxX` restricts to the leaf's outer free edge so we don't
  // touch the knuckle ring or the inner (x=0) seam edges.
  const outerX = xSign * LEAF_W;
  const filleted = (xSign > 0)
    ? fused.fillet(LEAF_FILLET, { inDirection: [0, 0, 1], minX: outerX - 0.5 })
    : fused.fillet(LEAF_FILLET, { inDirection: [0, 0, 1], maxX: outerX + 0.5 });

  // Screw holes: two per leaf at roughly ±20 mm along Y, 65% out along X.
  const xHole = xSign * (LEAF_W * 0.65);
  const drilled = BREP.cutAll([
    filleted,
    screwHole(xHole, -20),
    screwHole(xHole,  20),
  ]);

  // Countersink: chamfer the top rim of each screw hole. Pick the edges
  // by `nearPoint` (centered on the hole top, z=LEAF_TOP) + a tight
  // `withinDist` just larger than the hole radius — that uniquely
  // identifies the top circle of each hole.
  return drilled
    .chamfer(SCREW_CSK, {
      nearPoint: [xHole, -20, LEAF_TOP],
      withinDist: SCREW_R + 0.2,
    })
    .chamfer(SCREW_CSK, {
      nearPoint: [xHole,  20, LEAF_TOP],
      withinDist: SCREW_R + 0.2,
    });
}

// ---------------------------------------------------------------------------
// Build all knuckles and assign ownership.
// ---------------------------------------------------------------------------
const knuckleMid    = knuckle(Y_MID_MIN,   Y_MID_MAX);     // Leaf A owns
const knuckleOuterL = knuckle(Y_OUT_L_MIN, Y_OUT_L_MAX);   // Leaf B owns
const knuckleOuterR = knuckle(Y_OUT_R_MIN, Y_OUT_R_MAX);   // Leaf B owns

const leafA = buildLeaf(+1, [knuckleMid]);
const leafB = buildLeaf(-1, [knuckleOuterL, knuckleOuterR]);

// ---------------------------------------------------------------------------
// Pin: runs through all knuckles plus 1 mm cap each end.
// Total pin length = (Y_OUT_R_MAX - Y_OUT_L_MIN) + 2*PIN_CAP = 60 + 2 = 62.
// ---------------------------------------------------------------------------
const pinLen = (Y_OUT_R_MAX - Y_OUT_L_MIN) + 2 * PIN_CAP;
const pin = BREP.cylinder(PIN_R, pinLen)
  .rotate(-90, [1, 0, 0])
  .translate([0, Y_OUT_L_MIN - PIN_CAP, PIN_Z]);

// ---------------------------------------------------------------------------
// Final assembly. Fuse everything — the two leaves interlock through the
// knuckles, and the pin runs through all three. Because the leaves don't
// physically touch each other (the knuckle Y ranges are tiled with the pin
// providing the only connection), the fuse may yield componentCount = 2
// (hinge body + pin) or 1 (pin fuses leaves together via the knuckle bores)
// depending on how OCCT resolves the touching cylinders. Either is correct
// for a real hinge.
// ---------------------------------------------------------------------------
return BREP.fuseAll([leafA, leafB, pin]);
